```plantuml
@startuml
title CASSANDRA's Class Diagram

package it {
  package unipi {
    package lsmsdb {
      package stocksim {
        package lib {
          package database {
            class DBFactory
            class DB

            package cassandra {
              class CQLSessionException {
                + CQLSessionException()
              }

              class CassandraDBFactory {
                + {static} create()
                + getCassandraDB()
                - CassandraDBFactory()
              }

              class CassandraDB {
                - contactPoints : Vector<InetSocketAddress>
                - cqlSession : CqlSession
                - datacenter : String
                - hostnames : ArrayList<String>
                - ports : ArrayList<Integer>
                + connect()
                + disconnect()
                + execute()
                + prepareStatement()
                + query()
                + query()
                # CassandraDB()
              }

              class Main {
                + {static} main()
                + {static} testAggregation()
              }
            }

            DBFactory <|.. CassandraDBFactory
            DB <|.. CassandraDB
          }
        }
      }
    }
  }
}
@enduml
```
